// Optimized implementation: Hybrid Quicksort with Insertion Sort for small partitions,
// Median-of-Three pivot, and early exit for sorted data.

pub fn adaptive_sort<T: Ord + Clone>(arr: &mut [T]) {
    let len = arr.len();
    if len <= 1 {
        return;
    }

    // Check if already sorted (O(N) worst case, O(1) average for random)
    // This provides high adaptability to pre-sorted data
    let mut sorted = true;
    for i in 0..len-1 {
        if arr[i] > arr[i+1] {
            sorted = false;
            break;
        }
    }
    if sorted {
        return;
    }

    // Use insertion sort for small arrays
    if len <= 20 {
        insertion_sort(arr);
        return;
    }

    quicksort(arr, 0, len - 1);
}

fn quicksort<T: Ord + Clone>(arr: &mut [T], low: usize, high: usize) {
    if low < high {
        // Hybrid: Switch to insertion sort for small partitions
        if high - low < 20 {
            insertion_sort(&mut arr[low..=high]);
            return;
        }

        let pivot_index = partition(arr, low, high);

        if pivot_index > 0 {
            quicksort(arr, low, pivot_index - 1);
        }
        quicksort(arr, pivot_index + 1, high);
    }
}

fn partition<T: Ord + Clone>(arr: &mut [T], low: usize, high: usize) -> usize {
    // Median-of-three pivot selection to handle sorted/reverse-sorted data efficiently
    let mid = low + (high - low) / 2;
    if arr[mid] < arr[low] { arr.swap(low, mid); }
    if arr[high] < arr[low] { arr.swap(low, high); }
    if arr[high] < arr[mid] { arr.swap(mid, high); }

    // Place pivot (median) at high
    arr.swap(mid, high);
    let pivot = arr[high].clone();

    let mut i = low;
    for j in low..high {
        if arr[j] <= pivot {
            arr.swap(i, j);
            i += 1;
        }
    }

    arr.swap(i, high);
    i
}

fn insertion_sort<T: Ord>(arr: &mut [T]) {
    for i in 1..arr.len() {
        let mut j = i;
        while j > 0 && arr[j - 1] > arr[j] {
            arr.swap(j, j - 1);
            j -= 1;
        }
    }
}
